    productStatus: 'in stock',
    productPrice: '45.99'
  };

  let allCorrect = true;
  for (const [key, expectedValue] of Object.entries(expectedValues)) {
    const actualValue = window[key];
    if (actualValue !== expectedValue) {
      console.error(`Mismatch for ${key}: expected "${expectedValue}", got "${actualValue}"`);
      allCorrect = false;
    }
  }

  if (allCorrect) {
    console.log('✓ All product metadata variables verified successfully!\n');
  } else {
    console.error('✗ Some product metadata variables did not match expected values.\n');
  }

  return allCorrect;
}

